import "./menubar.css";

import { Menubar } from "radix-ui";
import { cn } from "tailwind-variants";

import { MenubarContext } from "./menubar.context";
import { menubarVariants } from "./menubar.variants";

export type MenubarRootProps = React.ComponentProps<typeof Menubar.Root>;

export const MenubarRoot = ({ className, ...props }: MenubarRootProps) => {
  const slots = menubarVariants();

  return (
    <MenubarContext value={{ slots }}>
      <Menubar.Root className={cn(slots.root(), className)} {...props} />
    </MenubarContext>
  );
};

import { Menubar } from "radix-ui";

export type MenubarMenuProps = React.ComponentProps<typeof Menubar.Menu>;

export const MenubarMenu = (props: MenubarMenuProps) => {
  return <Menubar.Menu {...props} />;
};

import { Menubar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useMenubarContext } from "./menubar.context";

export type MenubarTriggerProps = React.ComponentProps<typeof Menubar.Trigger>;

export const MenubarTrigger = ({ className, ...props }: MenubarTriggerProps) => {
  const { slots } = useMenubarContext();

  return <Menubar.Trigger className={cn(slots.trigger(), className)} {...props} />;
};

import { Menubar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useMenubarContext } from "./menubar.context";

export type MenubarContentProps = React.ComponentProps<typeof Menubar.Content>;

export const MenubarContent = ({
  align = "start",
  alignOffset = -4,
  className,
  sideOffset = 8,
  ...props
}: MenubarContentProps) => {
  const { slots } = useMenubarContext();

  return (
    <Menubar.Portal>
      <Menubar.Content
        align={align}
        alignOffset={alignOffset}
        className={cn(slots.content(), className)}
        sideOffset={sideOffset}
        {...props}
      />
    </Menubar.Portal>
  );
};

