import { createContext, useContext } from "react";

import { menubarVariants } from "./menubar.variants";

export type MenubarContext = {
  slots: ReturnType<typeof menubarVariants>;
};

export const MenubarContext = createContext<MenubarContext | null>(null);

export const useMenubarContext = () => {
  const context = useContext(MenubarContext);
  if (!context) {
    throw new Error("useMenubarContext must be used within a Menubar");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const menubarVariants = tv({
  slots: {
    checkbox: "menubar__checkbox-item",
    content: "menubar__content",
    indicator: "menubar__indicator",
    item: "menubar__item",
    label: "menubar__label",
    radio: "menubar__radio-item",
    root: "menubar",
    separator: "menubar__separator",
    shortcut: "menubar__shortcut",
    subContent: "menubar__sub-content",
    subTrigger: "menubar__sub-trigger",
    trigger: "menubar__trigger",
  },
});

export type MenubarVariants = VariantProps<typeof menubarVariants>;

.menubar {
  @apply bg-background flex h-9 items-center gap-1 rounded-md border p-1 shadow-sm;
}

.menubar__trigger {
  @apply flex cursor-default items-center rounded-sm px-3 py-1 text-sm font-medium outline-none select-none;

  &:focus {
    @apply bg-accent text-accent-foreground;
  }

  &[data-state="open"] {
    @apply bg-accent text-accent-foreground;
  }
}

.menubar__content {
  @apply bg-popover text-popover-foreground z-50 min-w-[12rem] overflow-hidden rounded-md border p-1 shadow-md;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

.menubar__item {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.menubar__checkbox-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.menubar__radio-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.menubar__indicator {
  @apply absolute left-2 inline-flex items-center justify-center;

  & svg {
    @apply size-3.5;
  }
}

.menubar__label {
  @apply text-muted-foreground px-2 py-1.5 text-xs font-semibold;
}

.menubar__separator {
  @apply bg-border -mx-1 my-1 h-px;
}

.menubar__shortcut {
  @apply text-muted-foreground ml-auto text-xs tracking-widest;
}

.menubar__sub-trigger {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-state="open"] {
    @apply bg-accent text-accent-foreground;
  }
}

.menubar__sub-content {
  @apply bg-popover text-popover-foreground z-50 min-w-[8rem] overflow-hidden rounded-md border p-1 shadow-lg;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

import { MenubarCheckboxItem } from "./menubar-checkbox-item";
import { MenubarContent } from "./menubar-content";
import { MenubarItem } from "./menubar-item";
import { MenubarLabel } from "./menubar-label";
import { MenubarMenu } from "./menubar-menu";
import { MenubarRadioItem } from "./menubar-radio-item";
import { MenubarRoot } from "./menubar-root";
import { MenubarSeparator } from "./menubar-separator";
import { MenubarShortcut } from "./menubar-shortcut";
import { MenubarSub, MenubarSubContent, MenubarSubTrigger } from "./menubar-sub";
import { MenubarTrigger } from "./menubar-trigger";

export const Menubar = {
  CheckboxItem: MenubarCheckboxItem,
  Content: MenubarContent,
  Item: MenubarItem,
  Label: MenubarLabel,
  Menu: MenubarMenu,
  RadioItem: MenubarRadioItem,
  Root: MenubarRoot,
  Separator: MenubarSeparator,
  Shortcut: MenubarShortcut,
  Sub: MenubarSub,
  SubContent: MenubarSubContent,
  SubTrigger: MenubarSubTrigger,
  Trigger: MenubarTrigger,
};

export {
  MenubarCheckboxItem,
  MenubarContent,
  MenubarItem,
  MenubarLabel,
  MenubarMenu,
  MenubarRadioItem,
  MenubarRoot,
  MenubarSeparator,
  MenubarShortcut,
  MenubarSub,
  MenubarSubContent,
  MenubarSubTrigger,
  MenubarTrigger,
};

export type { MenubarCheckboxItemProps } from "./menubar-checkbox-item";

export type { MenubarContentProps } from "./menubar-content";

export type { MenubarItemProps } from "./menubar-item";
export type { MenubarLabelProps } from "./menubar-label";
export type { MenubarMenuProps } from "./menubar-menu";
export type { MenubarRadioItemProps } from "./menubar-radio-item";
export type { MenubarRootProps } from "./menubar-root";
export type { MenubarSeparatorProps } from "./menubar-separator";
export type { MenubarShortcutProps } from "./menubar-shortcut";
export type {
  MenubarSubContentProps,
  MenubarSubProps,
  MenubarSubTriggerProps,
} from "./menubar-sub";
export type { MenubarTriggerProps } from "./menubar-trigger";
export { MenubarContext, useMenubarContext } from "./menubar.context";
export { type MenubarVariants, menubarVariants } from "./menubar.variants";
